43	/** Resolve a CSS color token to an rgb() string that Three.js can parse.
44	 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
45	 * Three.js does not support — routing through a DOM element forces the
46	 * browser to resolve it to "rgb(r, g, b)". */
47	function readColorToken(name: string, fallback: string): string {
48	  if (typeof document === 'undefined') return fallback;
49	  try {
50	    const el = document.createElement('div');
51	    el.style.display = 'none';
52	    el.style.color = `var(${name}, ${fallback})`;
53	    document.body.appendChild(el);
54	    const resolved = getComputedStyle(el).color;
55	    document.body.removeChild(el);
56	    return resolved || fallback;
57	  } catch {
58	    return fallback;
59	  }
60	}
