67	type WallElem = Extract<Element, { kind: 'wall' }>;
68	
69	/** Footprints use world XZ with z ← plan yMm */
70	
71	function xzBoundsMm(poly: Array<{ xMm: number; yMm: number }>): {
72	  minX: number;
73	  maxX: number;
74	  minZ: number;
75	  maxZ: number;
76	  cx: number;
77	  cz: number;
78	  spanX: number;
79	  spanZ: number;
80	} {
81	  let minX = Number.POSITIVE_INFINITY;
82	  let maxX = Number.NEGATIVE_INFINITY;
83	  let minZ = Number.POSITIVE_INFINITY;
84	  let maxZ = Number.NEGATIVE_INFINITY;
85	  for (const p of poly) {
86	    minX = Math.min(minX, p.xMm);
87	
88	    maxX = Math.max(maxX, p.xMm);
89	
90	    minZ = Math.min(minZ, p.yMm);
91	
92	    maxZ = Math.max(maxZ, p.yMm);
93	  }
94	
95	  const spanX = Math.max(maxX - minX, 1);
96	
97	  const spanZ = Math.max(maxZ - minZ, 1);
98	
99	  return {
100	    minX,
101	
102	    maxX,
103	
104	    minZ,
105	
106	    maxZ,
107	
108	    cx: (minX + maxX) / 2,
109	
110	    cz: (minZ + maxZ) / 2,
111	
112	    spanX,
113	
114	    spanZ,
115	  };
116	}
