149	function makeFloorSlabMesh(
150	  floor: Extract<Element, { kind: 'floor' }>,
151	  elementsById: Record<string, Element>,
152	  paint: ViewportPaintBundle | null,
153	): THREE.Mesh {
154	  const elev = elevationMForLevel(floor.levelId, elementsById);
155	  const th = THREE.MathUtils.clamp(floor.thicknessMm / 1000, 0.05, 1.8);
156	  const boundary = floor.boundaryMm ?? [];
157	
158	  // Build shape in shape-XY (plan X→shape X, plan Y negated→shape Y).
159	  // After ExtrudeGeometry + rotateX(-π/2): shape X→world X, extrude depth→world Y, −shapeY→world Z.
160	  const shape = new THREE.Shape(
161	    boundary.length >= 3
162	      ? boundary.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))
163	      : [
164	          new THREE.Vector2(0, 0),
165	          new THREE.Vector2(6, 0),
166	          new THREE.Vector2(6, -6),
167	          new THREE.Vector2(0, -6),
168	        ],
169	  );
170	
171	  // Punch holes for any slab openings hosted by this floor.
172	  for (const el of Object.values(elementsById)) {
173	    if (el.kind !== 'slab_opening' || el.hostFloorId !== floor.id) continue;
174	    const hPts = el.boundaryMm ?? [];
175	    if (hPts.length < 3) continue;
176	    shape.holes.push(
177	      new THREE.Path(hPts.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))),
178	    );
179	  }
180	
181	  const geom = new THREE.ExtrudeGeometry(shape, { depth: th, bevelEnabled: false });
182	  geom.rotateX(-Math.PI / 2);
183	
184	  const mesh = new THREE.Mesh(
185	    geom,
186	    new THREE.MeshStandardMaterial({
187	      color: categoryColorOr(paint, 'floor'),
188	      roughness: paint?.categories.floor.roughness ?? 0.9,
189	      transparent: true,
190	      opacity: 0.92,
191	    }),
192	  );
193	  mesh.position.set(0, elev, 0);
194	  mesh.userData.bimPickId = floor.id;
195	  return mesh;
196	}
