198	function makeRoofMassMesh(
199	  roof: Extract<Element, { kind: 'roof' }>,
200	  elementsById: Record<string, Element>,
201	  paint: ViewportPaintBundle | null,
202	): THREE.Mesh {
203	  const b = xzBoundsMm(roof.footprintMm ?? []);
204	
205	  const ov = THREE.MathUtils.clamp((roof.overhangMm ?? 0) / 1000, 0, 5);
206	
207	  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
208	  // Eave plate = top of the tallest wall at the reference level.
209	  // Without this, the box proxy sits inside the upper-storey walls and is invisible.
210	  const wallsAtRefLevel = Object.values(elementsById).filter(
211	    (e): e is WallElem => e.kind === 'wall' && (e as WallElem).levelId === roof.referenceLevelId,
212	  );
213	  const wallTopM =
214	    wallsAtRefLevel.length > 0
215	      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
216	      : 0;
217	  const eaveY = refElev + wallTopM;
218	
219	  const slopeRad = (THREE.MathUtils.clamp(Number(roof.slopeDeg ?? 25), 5, 70) * Math.PI) / 180;
220	  const spanXm = b.spanX / 1000;
221	  const spanZm = b.spanZ / 1000;
222	  const halfSpan = Math.min(spanXm, spanZm) / 2;
223	  const ridgeY = eaveY + halfSpan * Math.tan(slopeRad);
224	
225	  const ox0 = b.minX / 1000 - ov;
226	  const ox1 = b.maxX / 1000 + ov;
227	  const oz0 = b.minZ / 1000 - ov;
228	  const oz1 = b.maxZ / 1000 + ov;
229	
230	  // Triangulated gable mesh — ridge runs along the longer plan axis.
231	  let positions: number[];
232	  if (spanXm >= spanZm) {
233	    // Ridge east-west (along X); slopes drop to south (oz0) and north (oz1).
234	    const rz = (oz0 + oz1) / 2;
235	    positions = [
236	      // South slope
237	      ox0, eaveY, oz0,  ox1, eaveY, oz0,  ox0, ridgeY, rz,
238	      ox1, eaveY, oz0,  ox1, ridgeY, rz,  ox0, ridgeY, rz,
239	      // North slope
240	      ox0, ridgeY, rz,  ox1, ridgeY, rz,  ox0, eaveY, oz1,
241	      ox1, ridgeY, rz,  ox1, eaveY, oz1,  ox0, eaveY, oz1,
242	      // West gable
243	      ox0, eaveY, oz0,  ox0, ridgeY, rz,  ox0, eaveY, oz1,
244	      // East gable
245	      ox1, eaveY, oz0,  ox1, eaveY, oz1,  ox1, ridgeY, rz,
246	    ];
247	  } else {
248	    // Ridge north-south (along Z); slopes drop to west (ox0) and east (ox1).
249	    const rx = (ox0 + ox1) / 2;
250	    positions = [
251	      // West slope
252	      ox0, eaveY, oz0,  ox0, eaveY, oz1,  rx, ridgeY, oz0,
253	      ox0, eaveY, oz1,  rx, ridgeY, oz1,  rx, ridgeY, oz0,
254	      // East slope
255	      rx, ridgeY, oz0,  rx, ridgeY, oz1,  ox1, eaveY, oz0,
256	      rx, ridgeY, oz1,  ox1, eaveY, oz1,  ox1, eaveY, oz0,
257	      // South gable
258	      ox0, eaveY, oz0,  rx, ridgeY, oz0,  ox1, eaveY, oz0,
259	      // North gable
260	      ox0, eaveY, oz1,  ox1, eaveY, oz1,  rx, ridgeY, oz1,
261	    ];
262	  }
263	
264	  const geom = new THREE.BufferGeometry();
265	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
266	  geom.computeVertexNormals();
267	
268	  const mesh = new THREE.Mesh(
269	    geom,
270	    new THREE.MeshStandardMaterial({
271	      color: categoryColorOr(paint, 'roof'),
272	      transparent: true,
273	      opacity: 0.94,
274	      roughness: paint?.categories.roof.roughness ?? 0.74,
275	      metalness: 0.04,
276	      side: THREE.DoubleSide,
277	    }),
278	  );
279	  mesh.userData.bimPickId = roof.id;
280	  return mesh;
281	}
