283	function makeStairVolumeMesh(
284	  stair: Extract<Element, { kind: 'stair' }>,
285	  elementsById: Record<string, Element>,
286	  paint: ViewportPaintBundle | null,
287	  selectedId?: string,
288	): THREE.Mesh {
289	  const sx = stair.runStartMm.xMm / 1000;
290	
291	  const sz = stair.runStartMm.yMm / 1000;
292	
293	  const ex = stair.runEndMm.xMm / 1000;
294	
295	  const ez = stair.runEndMm.yMm / 1000;
296	
297	  const dx = ex - sx;
298	
299	  const dz = ez - sz;
300	
301	  const len = Math.max(1e-3, Math.hypot(dx, dz));
302	
303	  const width = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
304	
305	  const bl = elementsById[stair.baseLevelId];
306	
307	  const tl = elementsById[stair.topLevelId];
308	
309	  const riseMm =
310	    bl?.kind === 'level' && tl?.kind === 'level'
311	      ? Math.abs(tl.elevationMm - bl.elevationMm)
312	      : stair.riserMm * 16;
313	
314	  const rise = THREE.MathUtils.clamp(riseMm / 1000, 0.5, 12);
315	
316	  const elevBase = elevationMForLevel(stair.baseLevelId, elementsById);
317	
318	  const mesh = new THREE.Mesh(
319	    new THREE.BoxGeometry(len, rise, width),
320	
321	    new THREE.MeshStandardMaterial({
322	      color:
323	        stair.id === selectedId
324	          ? (paint?.selection.selectedColor ?? '#fcd34d')
325	          : categoryColorOr(paint, 'stair'),
326	    }),
327	  );
328	
329	  mesh.position.set(sx + dx / 2, elevBase + rise / 2, sz + dz / 2);
330	
331	  mesh.rotation.y = Math.atan2(dx, dz);
332	
333	  mesh.userData.bimPickId = stair.id;
334	
335	  return mesh;
336	}
