338	function makeWallMesh(
339	  wall: WallElem,
340	  elevM: number,
341	  paint: ViewportPaintBundle | null,
342	  selectedId?: string,
343	): THREE.Mesh {
344	  const sx = wall.start.xMm / 1000;
345	  const sz = wall.start.yMm / 1000;
346	  const ex = wall.end.xMm / 1000;
347	  const ez = wall.end.yMm / 1000;
348	  const dx = ex - sx;
349	  const dz = ez - sz;
350	  const len = Math.max(0.001, Math.hypot(dx, dz));
351	  const height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
352	  const thick = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
353	  const mesh = new THREE.Mesh(
354	    new THREE.BoxGeometry(len, height, thick),
355	    new THREE.MeshStandardMaterial({
356	      color:
357	        wall.id === selectedId
358	          ? (paint?.selection.selectedColor ?? '#fb923c')
359	          : categoryColorOr(paint, 'wall'),
360	      roughness: paint?.categories.wall.roughness ?? 0.85,
361	    }),
362	  );
363	  mesh.position.set(sx + dx / 2, elevM + height / 2, sz + dz / 2);
364	  mesh.rotation.y = Math.atan2(dz, dx);
365	  mesh.userData.bimPickId = wall.id;
366	  return mesh;
367	}
