369	function makeDoorMesh(
370	  door: Extract<Element, { kind: 'door' }>,
371	  wall: WallElem,
372	  elevM: number,
373	  paint: ViewportPaintBundle | null,
374	  sid?: string,
375	) {
376	  const { px, pz } = hostedXZ(door, wall);
377	  const height = THREE.MathUtils.clamp((wall.heightMm / 1000) * 0.86, 0.6, 2.2);
378	  const width = THREE.MathUtils.clamp(door.widthMm / 1000, 0.35, 4);
379	  const depth = THREE.MathUtils.clamp(wall.thicknessMm / 1000 + 0.08, 0.08, 2);
380	  const mesh = new THREE.Mesh(
381	    new THREE.BoxGeometry(width, height, depth),
382	    new THREE.MeshStandardMaterial({
383	      color:
384	        door.id === sid
385	          ? (paint?.selection.selectedColor ?? '#fde047')
386	          : categoryColorOr(paint, 'door'),
387	    }),
388	  );
389	  mesh.position.set(px, elevM + height / 2, pz);
390	  mesh.rotation.y = wallYaw(wall);
391	  mesh.userData.bimPickId = door.id;
392	  return mesh;
393	}
