395	function makeWindowMesh(
396	  win: Extract<Element, { kind: 'window' }>,
397	  wall: WallElem,
398	  elevM: number,
399	  paint: ViewportPaintBundle | null,
400	  sid?: string,
401	) {
402	  const { px, pz } = hostedXZ(win, wall);
403	  const sill = THREE.MathUtils.clamp(win.sillHeightMm / 1000, 0.06, wall.heightMm / 1000 - 0.08);
404	  const h = THREE.MathUtils.clamp(win.heightMm / 1000, 0.05, wall.heightMm / 1000 - sill - 0.06);
405	  const width = THREE.MathUtils.clamp(win.widthMm / 1000, 0.14, 4);
406	  const depth = THREE.MathUtils.clamp(wall.thicknessMm / 1000 + 0.02, 0.06, 1.5);
407	  const mesh = new THREE.Mesh(
408	    new THREE.BoxGeometry(width, h, depth),
409	    new THREE.MeshStandardMaterial({
410	      transparent: true,
411	      opacity: 0.84,
412	      color:
413	        win.id === sid
414	          ? (paint?.selection.selectedColor ?? '#ddd6fe')
415	          : categoryColorOr(paint, 'window'),
416	    }),
417	  );
418	  mesh.position.set(px, elevM + sill + h / 2, pz);
419	  mesh.rotation.y = wallYaw(wall);
420	  mesh.userData.bimPickId = win.id;
421	  return mesh;
422	}
