424	function makeRoomRibbon(
425	  room: Extract<Element, { kind: 'room' }>,
426	  elevM: number,
427	  paint: ViewportPaintBundle | null,
428	) {
429	  const pts = room.outlineMm.map(
430	    (p) => new THREE.Vector3(p.xMm / 1000, elevM + 0.035, p.yMm / 1000),
431	  );
432	  const geom = new THREE.BufferGeometry().setFromPoints(pts);
433	  const loop = new THREE.LineLoop(
434	    geom,
435	    new THREE.LineBasicMaterial({ color: paint?.selection.selectedColor ?? '#60a5fa' }),
436	  );
437	  loop.userData.bimPickId = room.id;
438	  return loop;
439	}
