441	function makeRailingMesh(
442	  railing: Extract<Element, { kind: 'railing' }>,
443	  elementsById: Record<string, Element>,
444	  paint: ViewportPaintBundle | null,
445	): THREE.Group {
446	  const group = new THREE.Group();
447	  group.userData.bimPickId = railing.id;
448	
449	  const guardH = THREE.MathUtils.clamp((railing.guardHeightMm ?? 1050) / 1000, 0.5, 2.2);
450	  const pts = railing.pathMm ?? [];
451	  if (pts.length < 2) return group;
452	
453	  const stair = railing.hostedStairId ? elementsById[railing.hostedStairId] : null;
454	  const baseElev =
455	    stair?.kind === 'stair' ? elevationMForLevel(stair.baseLevelId, elementsById) : 0;
456	  const topElev =
457	    stair?.kind === 'stair' ? elevationMForLevel(stair.topLevelId, elementsById) : baseElev;
458	
459	  let totalPlanLen = 0;
460	  for (let i = 1; i < pts.length; i++) {
461	    totalPlanLen += Math.hypot(
462	      (pts[i]!.xMm - pts[i - 1]!.xMm) / 1000,
463	      (pts[i]!.yMm - pts[i - 1]!.yMm) / 1000,
464	    );
465	  }
466	
467	  const mat = new THREE.MeshStandardMaterial({
468	    color: categoryColorOr(paint, 'railing'),
469	    roughness: paint?.categories.railing.roughness ?? 0.6,
470	    metalness: paint?.categories.railing.metalness ?? 0.3,
471	  });
472	
473	  let cumLen = 0;
474	  for (let i = 0; i < pts.length - 1; i++) {
475	    const a = pts[i]!;
476	    const b = pts[i + 1]!;
477	    const ax = a.xMm / 1000,
478	      az = a.yMm / 1000;
479	    const bx = b.xMm / 1000,
480	      bz = b.yMm / 1000;
481	    const planSeg = Math.max(0.001, Math.hypot(bx - ax, bz - az));
482	    const tA = totalPlanLen > 0 ? cumLen / totalPlanLen : 0;
483	    cumLen += planSeg;
484	    const tB = totalPlanLen > 0 ? cumLen / totalPlanLen : 1;
485	    const elevA = baseElev + tA * (topElev - baseElev) + guardH;
486	    const elevB = baseElev + tB * (topElev - baseElev) + guardH;
487	    const riseY = elevB - elevA;
488	
489	    const railLen = Math.sqrt(planSeg * planSeg + riseY * riseY);
490	    const rail = new THREE.Mesh(new THREE.BoxGeometry(railLen, 0.05, 0.05), mat);
491	    rail.position.set((ax + bx) / 2, (elevA + elevB) / 2, (az + bz) / 2);
492	    const dir = new THREE.Vector3(bx - ax, riseY, bz - az).normalize();
493	    rail.quaternion.setFromUnitVectors(new THREE.Vector3(1, 0, 0), dir);
494	    group.add(rail);
495	  }
496	
497	  return group;
498	}
