500	function makeSiteMesh(
501	  site: Extract<Element, { kind: 'site' }>,
502	  elementsById: Record<string, Element>,
503	  paint: ViewportPaintBundle | null,
504	): THREE.Mesh {
505	  const elev = elevationMForLevel(site.referenceLevelId, elementsById);
506	  const baseOffset = (site.baseOffsetMm ?? 0) / 1000;
507	  const padTh = THREE.MathUtils.clamp((site.padThicknessMm ?? 150) / 1000, 0.05, 2);
508	  const boundary = site.boundaryMm ?? [];
509	
510	  const shape = new THREE.Shape(
511	    boundary.length >= 3
512	      ? boundary.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))
513	      : [
514	          new THREE.Vector2(-20, -20),
515	          new THREE.Vector2(20, -20),
516	          new THREE.Vector2(20, 20),
517	          new THREE.Vector2(-20, 20),
518	        ],
519	  );
520	
521	  const geom = new THREE.ExtrudeGeometry(shape, { depth: padTh, bevelEnabled: false });
522	  geom.rotateX(-Math.PI / 2);
523	
524	  const mesh = new THREE.Mesh(
525	    geom,
526	    new THREE.MeshStandardMaterial({
527	      color: categoryColorOr(paint, 'site'),
528	      roughness: paint?.categories.site.roughness ?? 0.95,
529	      metalness: paint?.categories.site.metalness ?? 0.0,
530	      transparent: true,
531	      opacity: 0.85,
532	    }),
533	  );
534	  mesh.position.set(0, elev + baseOffset - padTh, 0);
535	  mesh.userData.bimPickId = site.id;
536	  return mesh;
537	}
