542	  switch (e.kind) {
543	    case 'wall':
544	      return 'wall';
545	    case 'floor':
546	      return 'floor';
547	    case 'roof':
548	      return 'roof';
549	    case 'stair':
550	      return 'stair';
551	    case 'door':
552	      return 'door';
553	    case 'window':
554	      return 'window';
555	    case 'room':
556	      return 'room';
557	    case 'railing':
558	      return 'railing';
559	    case 'site':
560	      return 'site';
561	    default:
562	      return null;
